#include <stdio.h>
#include <string.h>

int main() {
    char A[201], B[2000001], C[201];
    scanf("%s %s %s", A, B, C);
    int lenA = strlen(A), lenB = strlen(B);
    int result = 0;
    for (int i = 0; i < lenB; i++) {
        for (int j = 1; j <= lenA && i + j <= lenB; j++) {
            int mismatches = 0;
            bool valid = true;
            for (int k = 0; k < j; k++) {
                if (A[k] != B[i + k]) {
                    if (C[k] == '1') {
                        mismatches++;
                    } else {
                        valid = false;
                        break;
                    }
                }
            }
            if (valid && mismatches <= 2) {
                result = (result + j * j) % 1000000007;
            }
        }
    }
    printf("%d\n", result);
    return 0;
}

